class Shipping {
  calculatePrice(order: { type: string }) {
    switch (order.type) {
      case 'STANDARD': return 5;
      case 'EXPRESS': return 20;
      case 'INTERNATIONAL': return 50;
    }
  }
}

class Invoice {
  constructor(private mode: 'retail'|'wholesale') {}
  calculateTax(amount: number) {
    if (this.mode === 'retail') return amount * 0.1;
    if (this.mode === 'wholesale') return amount * 0.06;
    return 0;
  }
}

// Version A: central conditional
class ReportA {
  constructor(private format: 'pdf'|'html') {}
  render(data: string) {
    if (this.format === 'pdf') return `PDF:${data}`;
    if (this.format === 'html') return `<html>${data}</html>`;
    return data;
  }
}

// Version B: distinct subclasses
abstract class ReportB {
  abstract render(data: string): string;
}
class PdfReport extends ReportB { render(data: string){ return `PDF:${data}` } }
class HtmlReport extends ReportB { render(data: string){ return `<html>${data}</html>` } }
